1	import express from 'express';
2	import cors from 'cors';
3	import { fileURLToPath } from 'node:url';
4	import { resolve, dirname, join } from 'node:path';
5	import commentsRouter from './api/comments.js';
6	import cardsRouter from './api/cards.js';
7	import { initWs } from './ws/broadcaster.js';
8	import { initDb } from './db/queries.js';
9	
10	const __dirname = dirname(fileURLToPath(import.meta.url));
11	
12	function createApp() {
13	  const app = express();
14	  const isProduction = process.env.NODE_ENV === 'production';
15	
16	  // ── Middleware ────────────────────────────────────────────────────────────
17	  // NOTE: origin:'*' + credentials:true is invalid per CORS spec (browsers reject it).
18	  // Use origin:true (reflect request Origin) in dev so credentials can coexist if needed.
19	  app.use(cors({
20	    origin: isProduction ? false : true, // 'true' reflects the request's Origin header
21	    credentials: true,
22	  }));
23	  app.use(express.json());
24	
25	  // ── API Routes ────────────────────────────────────────────────────────────
26	  app.use('/api', commentsRouter);
27	  app.use('/api', cardsRouter);
28	
29	  // ── Routes ────────────────────────────────────────────────────────────────
30	  app.get('/health', (_req, res) => res.json({ ok: true }));
31	
32	  // Dev/test-only routes (not in production)
33	  if (!isProduction) {
34	    app.post('/dev/echo', (req, res) => res.json(req.body));
35	    app.get('/dev/error', (req, res, next) => {
36	      const err = new Error('Test error');
37	      err.status = req.query.status ? parseInt(req.query.status, 10) : 500;
38	      next(err);
39	    });
40	  }
41	
42	  // ── Static files (production) ─────────────────────────────────────────────
43	  if (isProduction) {
44	    const distPath = join(__dirname, '..', 'client', 'dist');
45	    app.use(express.static(distPath));
46	    app.get('*', (_req, res) =>
47	      res.sendFile(join(distPath, 'index.html'))
48	    );
49	  }
50	
51	  // ── 404 handler ───────────────────────────────────────────────────────────
52	  app.use((_req, res) => res.status(404).json({ error: 'Not Found' }));
53	
54	  // ── Error handler ─────────────────────────────────────────────────────────
55	  // eslint-disable-next-line no-unused-vars
56	  app.use((err, _req, res, _next) => {
57	    const status = err.status || err.statusCode || 500;
58	    res.status(status).json({ error: err.message || 'Internal Server Error' });
59	  });
60	
61	  return app;
62	}
63	
64	// Start when run as the entry point
65	// resolve() normalises relative paths before comparing
66	if (resolve(process.argv[1]) === fileURLToPath(import.meta.url)) {
67	  const dbPath = process.env.DB_PATH || 'data/kanban.db';
68	  initDb(dbPath);
69	  const app = createApp();
70	  const PORT = process.env.PORT || 3001;
71	  const server = app.listen(PORT, () => console.log(`Server running on port ${PORT}`));
72	  initWs(server);
73	}
74	
75	export { createApp };
76

1	import { Router } from 'express';
2	import { getCards, createCard, updateCard, deleteCard, moveCard, NotFoundError } from '../db/queries.js';
3	import { broadcast } from '../ws/broadcaster.js';
4	
5	const router = Router();
6	
7	// GET /api/cards
8	router.get('/cards', (_req, res, next) => {
9	  try {
10	    const cards = getCards();
11	    return res.status(200).json(cards);
12	  } catch (err) {
13	    next(err);
14	  }
15	});
16	
17	// POST /api/cards
18	router.post('/cards', (req, res, next) => {
19	  const { title, assignee, column, description } = req.body ?? {};
20	  if (!title) {
21	    return res.status(400).json({ error: 'title is required' });
22	  }
23	  try {
24	    const card = createCard({ title, assignee, column, description });
25	    try { broadcast('card:created', card); } catch { /* isolate broadcast errors */ }
26	    return res.status(201).json(card);
27	  } catch (err) {
28	    next(err);
29	  }
30	});
31	
32	// PATCH /api/cards/:id
33	const CARD_UPDATE_ALLOWED = ['title', 'assignee', 'column', 'description', 'position'];
34	router.patch('/cards/:id', (req, res, next) => {
35	  const updateData = req.body ?? {};
36	  try {
37	    const card = updateCard(req.params.id, updateData);
38	    // Only broadcast when at least one recognized field was in the request body,
39	    // meaning updateCard actually performed a DB write. An empty or unrecognized-only
40	    // body causes updateCard to return the card unchanged (no DB write), so no broadcast.
41	    if (Object.keys(updateData).some(k => CARD_UPDATE_ALLOWED.includes(k))) {
42	      try { broadcast('card:updated', card); } catch { /* isolate broadcast errors */ }
43	    }
44	    return res.status(200).json(card);
45	  } catch (err) {
46	    if (err instanceof NotFoundError) {
47	      return res.status(404).json({ error: err.message });
48	    }
49	    next(err);
50	  }
51	});
52	
53	// DELETE /api/cards/:id
54	router.delete('/cards/:id', (req, res, next) => {
55	  try {
56	    deleteCard(req.params.id);
57	    try { broadcast('card:deleted', { id: req.params.id }); } catch { /* isolate */ }
58	    return res.status(204).send();
59	  } catch (err) {
60	    if (err instanceof NotFoundError) {
61	      return res.status(404).json({ error: err.message });
62	    }
63	    next(err);
64	  }
65	});
66	
67	// PATCH /api/cards/:id/move
68	router.patch('/cards/:id/move', (req, res, next) => {
69	  const { column, position } = req.body ?? {};
70	  if (!column || position === undefined || position === null) {
71	    return res.status(400).json({ error: 'column and position are required' });
72	  }
73	  try {
74	    const card = moveCard(req.params.id, column, position);
75	    try { broadcast('card:moved', card); } catch { /* isolate */ }
76	    return res.status(200).json(card);
77	  } catch (err) {
78	    if (err instanceof NotFoundError) {
79	      return res.status(404).json({ error: err.message });
80	    }
81	    next(err);
82	  }
83	});
84	
85	export default router;
