146	// ── Subtask 3: Health endpoint and error handling ─────────────────────────────
147	
148	describe('GET /health', () => {
149	  let server, baseUrl;
150	
151	  before(async () => {
152	    const app = createApp();
153	    ({ server, baseUrl } = await startTestServer(app));
154	  });
155	
156	  after(async () => {
157	    await stopServer(server);
