6	export default function CardTile({ card, onCardClick, onUpdate }) {
7	  const [isEditingTitle, setIsEditingTitle]       = useState(false)
8	  const [editTitle, setEditTitle]                 = useState(card.title)
9	  const [isEditingAssignee, setIsEditingAssignee] = useState(false)
10	  const [editAssignee, setEditAssignee]           = useState(card.assignee ?? '')
11	  const [isSaving, setIsSaving]                   = useState(false)
12	  const [saveError, setSaveError]                 = useState(null)
13	  const skipTitleBlurRef                          = useRef(false)
14	  const skipAssigneeBlurRef                       = useRef(false)
15	  const titleInputRef                             = useRef(null)
16	  const assigneeInputRef                          = useRef(null)
17	
18	  const { attributes, listeners, setNodeRef, transform, transition, isDragging } = useSortable({ id: card.id })
19	
20	  const style = {
21	    transform: CSS.Transform.toString(transform),
22	    transition,
23	  }
24	
25	  // Auto-focus input when entering edit mode (mirrors CardModal pattern)
26	  useEffect(() => {
27	    if (isEditingTitle && titleInputRef.current) titleInputRef.current.focus()
28	  }, [isEditingTitle])
29	
30	  useEffect(() => {
31	    if (isEditingAssignee && assigneeInputRef.current) assigneeInputRef.current.focus()
32	  }, [isEditingAssignee])
33	
34	  async function handleSaveTitle() {
35	    if (editTitle.trim() === '') { setSaveError('Title is required'); return }
36	    setIsSaving(true); setSaveError(null)
37	    try {
38	      await onUpdate(card.id, { title: editTitle })
39	      setIsEditingTitle(false)
40	    } catch (err) {
41	      setSaveError(err.message)
42	    } finally { setIsSaving(false) }
43	  }
44	
45	  async function handleSaveAssignee() {
46	    setIsSaving(true); setSaveError(null)
