77	      aria-label={card.title}
78	      {...attributes}
79	      {...restListeners}
80	    >
81	      {/* Title */}
82	      {isEditingTitle ? (
83	        <div className="card-tile-field-edit">
84	          <input
85	            ref={titleInputRef}
86	            aria-label="Edit title"
87	            value={editTitle}
