89	            onKeyDown={e => {
90	              if (e.key === 'Enter')  { skipTitleBlurRef.current = true; handleSaveTitle() }
91	              if (e.key === 'Escape') { skipTitleBlurRef.current = true; setIsEditingTitle(false); setEditTitle(card.title); setSaveError(null) }
92	            }}
93	            onBlur={() => {
94	              if (skipTitleBlurRef.current) { skipTitleBlurRef.current = false; return }
95	              handleSaveTitle()
96	            }}
97	          />
98	          {isSaving && <span aria-label="Saving">Saving…</span>}
99	        </div>
100	      ) : (
101	        <h3
102	          className="card-tile-title"
103	          onClick={e => {
104	            e.stopPropagation()
105	            setEditTitle(card.title)
106	            setIsEditingTitle(true)
107	            // Mutual exclusivity: close assignee edit if open
108	            setIsEditingAssignee(false)
109	            setEditAssignee(card.assignee ?? '')
110	            setSaveError(null)
111	          }}
112	        >
113	          {card.title}
114	        </h3>
115	      )}
116	
117	      {/* Assignee */}
118	      {isEditingAssignee ? (
119	        <div className="card-tile-field-edit">
120	          <input
121	            ref={assigneeInputRef}
122	            aria-label="Edit assignee"
123	            value={editAssignee}
124	            onChange={e => setEditAssignee(e.target.value)}
125	            onKeyDown={e => {
126	              if (e.key === 'Enter')  { skipAssigneeBlurRef.current = true; handleSaveAssignee() }
127	              if (e.key === 'Escape') { skipAssigneeBlurRef.current = true; setIsEditingAssignee(false); setEditAssignee(card.assignee ?? ''); setSaveError(null) }
128	            }}
129	            onBlur={() => {
130	              if (skipAssigneeBlurRef.current) { skipAssigneeBlurRef.current = false; return }
131	              handleSaveAssignee()
132	            }}
133	          />
134	          {isSaving && <span aria-label="Saving">Saving…</span>}
135	        </div>
136	      ) : (
137	        <p
138	          className="card-tile-assignee"
139	          onClick={e => {
140	            e.stopPropagation()
141	            setEditAssignee(card.assignee ?? '')
142	            setIsEditingAssignee(true)
143	            // Mutual exclusivity: close title edit if open
144	            setIsEditingTitle(false)
145	            setEditTitle(card.title)
146	            setSaveError(null)
147	          }}
148	        >
149	          {card.assignee ?? 'Unassigned'}
150	        </p>
151	      )}
152	
153	      {card.description && <p className="card-tile-description">{card.description}</p>}
154	      {saveError && <p role="alert" className="card-tile-error">{saveError}</p>}
155	    </div>
156	  )
157	}
