22	  const titleInputRef       = useRef(null)
23	  const assigneeInputRef    = useRef(null)
24	  const skipTitleBlurRef    = useRef(false)
25	  const skipAssigneeBlurRef = useRef(false)
26	
27	  // Focus effects
28	  useEffect(() => {
29	    if (isEditingTitle && titleInputRef.current) titleInputRef.current.focus()
30	  }, [isEditingTitle])
31	
32	  useEffect(() => {
33	    if (isEditingAssignee && assigneeInputRef.current) assigneeInputRef.current.focus()
34	  }, [isEditingAssignee])
35	
36	  // Escape key handler — replaces the original handler
37	  useEffect(() => {
38	    function onKey(e) {
39	      if (e.key !== 'Escape') return
40	      if (isEditingTitle) {
41	        skipTitleBlurRef.current = true   // prevent blur from triggering save
42	        setIsEditingTitle(false); setEditTitle(card.title); setSaveError(null)
43	      } else if (isEditingAssignee) {
44	        skipAssigneeBlurRef.current = true   // prevent blur from triggering save
45	        setIsEditingAssignee(false); setEditAssignee(card.assignee ?? ''); setSaveError(null)
46	      } else if (isEditingDescription) {
47	        // BlockEditor owns its own Escape handler; CardModal just prevents modal close
48	      } else {
49	        onClose()
50	      }
51	    }
52	    document.addEventListener('keydown', onKey)
53	    return () => document.removeEventListener('keydown', onKey)
54	  }, [onClose, isEditingTitle, isEditingAssignee, isEditingDescription, card.title, card.assignee])
55	
56	  // Save handlers
57	  async function handleSaveTitle() {
58	    if (editTitle.trim() === '') {
59	      setSaveError('Title is required')
60	      return
61	    }
62	    setIsSaving(true); setSaveError(null)
63	    try {
64	      await onUpdate(card.id, { title: editTitle })
