110	        </button>
111	
112	        {/* 2. Title field (editable) */}
113	        {isEditingTitle ? (
114	          <div className="modal-field-edit">
115	            <input
116	              ref={titleInputRef}
117	              aria-label="Title"
118	              value={editTitle}
119	              onChange={e => setEditTitle(e.target.value)}
120	              onKeyDown={e => { if (e.key === 'Enter') { skipTitleBlurRef.current = true; handleSaveTitle() } }}
121	              onBlur={() => {
122	                if (skipTitleBlurRef.current) { skipTitleBlurRef.current = false; return }
123	                handleSaveTitle()
124	              }}
125	            />
