127	              {isSaving ? 'Saving…' : 'Save'}
128	            </button>
129	            <button
130	              aria-label="Cancel"
131	              disabled={isSaving}
132	              onMouseDown={() => { skipTitleBlurRef.current = true }}
133	              onClick={() => { setIsEditingTitle(false); setEditTitle(card.title); setSaveError(null) }}
134	            >
135	              Cancel
136	            </button>
137	          </div>
138	        ) : (
139	          <div className="modal-field-view">
140	            <h2 className="modal-title">{card.title}</h2>
141	            <button
142	              aria-label="Edit title"
143	              onClick={() => {
144	                setIsEditingTitle(true); setEditTitle(card.title)
145	                // Mutual exclusivity: close assignee edit if open
146	                setIsEditingAssignee(false); setEditAssignee(card.assignee ?? ''); setSaveError(null)
147	              }}
148	            >
149	              Edit
150	            </button>
151	          </div>
152	        )}
153	
154	        {/* 3. Assignee field (editable) */}
155	        {isEditingAssignee ? (
156	          <div className="modal-field-edit">
157	            <input
158	              ref={assigneeInputRef}
159	              aria-label="Assignee"
