168	            <button aria-label="Save" onMouseDown={() => { skipAssigneeBlurRef.current = true }} onClick={handleSaveAssignee} disabled={isSaving}>
169	              {isSaving ? 'Saving…' : 'Save'}
170	            </button>
171	            <button
172	              aria-label="Cancel"
173	              disabled={isSaving}
174	              onMouseDown={() => { skipAssigneeBlurRef.current = true }}
175	              onClick={() => { setIsEditingAssignee(false); setEditAssignee(card.assignee ?? ''); setSaveError(null) }}
176	            >
177	              Cancel
178	            </button>
179	          </div>
180	        ) : (
181	          <div className="modal-field-view">
182	            <p className="modal-assignee">
183	              <strong>Assignee:</strong> {card.assignee ?? 'Unassigned'}
184	            </p>
185	            <button
186	              aria-label="Edit assignee"
187	              onClick={() => {
188	                setIsEditingAssignee(true); setEditAssignee(card.assignee ?? '')
189	                // Mutual exclusivity: close title edit if open
190	                setIsEditingTitle(false); setEditTitle(card.title); setSaveError(null)
191	              }}
192	            >
193	              Edit
194	            </button>
195	          </div>
196	        )}
197	
198	        {/* 4. Description (BlockNote editor) */}
199	        <BlockEditor
200	          content={card.description}
