202	          onEditingChange={setIsEditingDescription}
203	        />
204	
205	        {/* 5. Error alert */}
206	        {saveError && <p role="alert" className="modal-error">{saveError}</p>}
207	
208	        {/* 6. Comments section */}
209	        <CommentList
210	          comments={card.comments}
211	          onAddComment={(data) => onAddComment(card.id, data)}
212	        />
213	
214	        {/* 7. Delete button / confirmation */}
215	        {showDeleteConfirm ? (
216	          <div className="modal-delete-confirm" role="region" aria-label="Delete confirmation">
217	            <p>Are you sure you want to delete this card?</p>
218	            <button
219	              aria-label="Confirm delete"
220	              onClick={handleConfirmDelete}
221	              disabled={isDeleting}
222	            >
223	              {isDeleting ? 'Deleting…' : 'Confirm delete'}
