8	async function startTestServerWithWs(app) {
9	  return new Promise((resolve) => {
10	    const server = app.listen(0, () => {
11	      const { port } = server.address();
12	      initWs(server);
13	      resolve({ server, baseUrl: `http://localhost:${port}`, wsUrl: `ws://localhost:${port}` });
14	    });
15	  });
16	}
17	
18	async function stopTestServer(server) {
19	  await closeWs();
20	  return new Promise((resolve) => server.close(resolve));
21	}
22	
23	function connectWsClient(wsUrl) {
24	  return new Promise((resolve, reject) => {
25	    const ws = new WebSocket(wsUrl);
26	    ws.once('open', () => resolve(ws));
27	    ws.once('error', reject);
28	  });
29	}
30	
31	function waitForMessage(ws) {
32	  return new Promise((resolve) => {
33	    ws.once('message', (data) => resolve(JSON.parse(data.toString())));
34	  });
35	}
36	
37	function closeWsClient(ws) {
38	  return new Promise((resolve) => {
39	    if (ws.readyState === WebSocket.CLOSED) return resolve();
40	    ws.once('close', resolve);
41	    ws.close();
42	  });
43	}
44	
45	function withTimeout(promise, ms = 500) {
46	  return Promise.race([
47	    promise,
48	    new Promise((_, reject) => setTimeout(() => reject(new Error(`Timed out after ${ms}ms`)), ms)),
49	  ]);
50	}
